"""Allocation strategies — the extensibility SEAM (Strategy pattern).

The LockerService never knows HOW a compartment is chosen. It asks a strategy.
Swapping policy = new class, zero core changes (Open/Closed).
"""
from __future__ import annotations

from abc import ABC, abstractmethod
from typing import Optional

from models import CompartmentSize, Compartment, Locker


class AllocationStrategy(ABC):
    # ── WHY THIS CLASS ──
    # The seam. Core depends on this abstraction, not on "how to pick a box".
    # 🎙️ "The service asks the strategy which compartment to use — it has no idea
    #     whether that's best-fit or nearest-door."
    @abstractmethod
    def select(self, locker: Locker, size: CompartmentSize) -> Optional[Compartment]:
        ...


class BestFitAllocation(AllocationStrategy):
    """Pick the SMALLEST available compartment that still fits the package."""

    def select(self, locker: Locker, size: CompartmentSize) -> Optional[Compartment]:
        candidates = locker.fitting_available(size)
        if not candidates:
            return None
        # WHY: smallest fitting box first -> don't waste a LARGE box on a SMALL
        #      package (reduces fragmentation). Tie-break by id for determinism.
        # ⚠️ FOLLOW-UP: "Why best-fit not first-fit?"
        #    -> "First-fit can burn big boxes on small packages and reject a later
        #        big package the station could have served. Best-fit keeps big boxes free."
        return min(candidates, key=lambda c: (c.size, c.id))


class NearestDoorAllocation(AllocationStrategy):
    """Alt policy: assume lower id == closer to the door (accessibility)."""

    def select(self, locker: Locker, size: CompartmentSize) -> Optional[Compartment]:
        candidates = locker.fitting_available(size)
        if not candidates:
            return None
        return min(candidates, key=lambda c: c.id)

"""Notification sinks (Observer pattern) — decouple SMS/email/push from booking."""
from __future__ import annotations

from abc import ABC, abstractmethod
from typing import Any


class NotificationObserver(ABC):
    # ── WHY THIS CLASS ──
    # Keeps the booking path independent of HOW users are notified.
    @abstractmethod
    def notify(self, event: str, data: dict[str, Any]) -> None:
        ...


class ConsoleNotifier(NotificationObserver):
    def notify(self, event: str, data: dict[str, Any]) -> None:
        print(f"[NOTIFY] {event}: {data}")


class CollectingNotifier(NotificationObserver):
    # WHY: a test double that records events so assertions can check them.
    def __init__(self) -> None:
        self.events: list[tuple[str, dict[str, Any]]] = []

    def notify(self, event: str, data: dict[str, Any]) -> None:
        self.events.append((event, data))
